export default function Header() {
  const [menuOpen, setMenuOpen] = useState(false);
  const { pathname } = useLocation();

  return (
    <header className={styles.header}>
      <div className={`container ${styles.inner}`}>
        <Link to="/" className={styles.logo} onClick={() => setMenuOpen(false)}>
          <LogoMark />
          <span className={styles.logoWord}>DarkAuth</span>
        </Link>

        <nav className={styles.nav} aria-label="Main navigation">
          {NAV_LINKS.map((link) => (
            <Link
              key={link.to}
              to={link.to}
              className={`${styles.navLink}${pathname.startsWith(link.to) ? ` ${styles.active}` : ""}`}
            >
              {link.label}
            </Link>
          ))}
        </nav>

        <div className={styles.actions}>
          <ThemeToggle />
          <a
            href="https://github.com/puzed/darkauth"
            className={styles.btnGhost}
            target="_blank"
            rel="noopener noreferrer"
            aria-label="View DarkAuth on GitHub"
            title="View DarkAuth on GitHub"
            data-icon-only
          >
            <GithubIcon />
          </a>
          <Link to="/developers/quickstart" className={styles.btnPrimary}>
            Get Started
          </Link>
        </div>

        <button
          className={styles.menuBtn}
          onClick={() => setMenuOpen((o) => !o)}
          aria-expanded={menuOpen}
          aria-label="Toggle navigation menu"
        >
          <span className={styles.menuLine} />
          <span className={styles.menuLine} />
          <span className={styles.menuLine} />
        </button>
      </div>

      <nav
        className={`${styles.drawer}${menuOpen ? ` ${styles.open}` : ""}`}
        aria-label="Mobile navigation"
      >
        {NAV_LINKS.map((link) => (
          <Link
            key={link.to}
            to={link.to}
            className={styles.drawerLink}
            onClick={() => setMenuOpen(false)}
          >
            {link.label}
          </Link>
        ))}
        <div className={styles.drawerActions}>
          <ThemeToggle />
          <a
            href="https://github.com/puzed/darkauth"
            className={styles.btnGhost}
            target="_blank"
            rel="noopener noreferrer"
            aria-label="View DarkAuth on GitHub"
            title="View DarkAuth on GitHub"
            data-icon-only
            onClick={() => setMenuOpen(false)}
          >
            <GithubIcon />
          </a>
          <Link
            to="/developers/quickstart"
            className={styles.btnPrimary}
            onClick={() => setMenuOpen(false)}
          >
            Get Started
          </Link>
        </div>
      </nav>
    </header>
  );
}
